        private void BindCondition()
        {

            string qry112Q = "SELECT * FROM OutPMT where PermitNumber='" + Permitnum + "'";
            obj.dr = obj.ret_dr(qry112Q);
            while (obj.dr.Read())
            {
                LblPermitNo.Text = obj.dr["PermitNumber"].ToString();

                Convert.ToDateTime(obj.dr["EndDate"].ToString()).ToString("dd/MM/yyyy");
                string validityperiod = Convert.ToDateTime(obj.dr["StartDate"].ToString()).ToString("dd/MM/yyyy") + "-" + Convert.ToDateTime(obj.dr["EndDate"].ToString()).ToString("dd/MM/yyyy"); ;
                LblValidPeriod.Text = validityperiod;
                string a = obj.dr["PermitApprovalDatetime"].ToString();
                // string a = "20190321152148SST";
                string year = a.Substring(0, 4);
                string month = a.Substring(4, 2);
                string date = a.Substring(6, 2);
                string hour = a.Substring(8, 2);
                string minit = a.Substring(10, 2);
                string sec = a.Substring(12, 2);


                string finalappdate = date + "-" + month + "-" + year + " " + hour + ":" + minit + ":" + sec;
                //  20190321152148SST
                LblApprovedDate.Text = finalappdate;
            }

            string constr = ConfigurationManager.ConnectionStrings["Mycon"].ConnectionString;
            string status = "";
            OutClass select = new OutClass();
            obj.dr = obj.ret_dr("Select * from OutHeaderTbl Where MSGId='" + msgid + "'");
            if (obj.dr.Read())
            {
                status = obj.dr["Status"].ToString();
                lblstatus.Text = obj.dr["Status"].ToString();
                lblmsgid.Text = obj.dr["MSGId"].ToString();
                lbljobid.Text = obj.dr["JobId"].ToString();
                lbldecdate.Text = obj.dr["TouchTime"].ToString();
                lblcreate.Text = obj.dr["TouchUser"].ToString();
            }
            //if (!string.IsNullOrWhiteSpace(Permitnum))
            //{
            //    OutClass obj1 = new OutClass();
            //    obj1.dr = obj1.ret_dr("Select * from OutHeaderTbl Where PermitNumber='" + Permitnum + "'");
            //    if (obj1.dr.Read())
            //    {
            //        msgid = obj1.dr["MSGId"].ToString();
            //    }
            //}

            if (status == "APR")
            {

                using (SqlConnection con = new SqlConnection(constr))
                {
                    using (SqlCommand cmd = new SqlCommand("SELECT Sno as SNo, ConditionCode as Code, ConditionDescription as Description FROM OutPMT Where PermitNumber='" + Permitnum + "' Order by Sno"))
                    {
                        using (SqlDataAdapter sda = new SqlDataAdapter())
                        {
                            cmd.Connection = con;
                            sda.SelectCommand = cmd;
                            using (DataTable dt = new DataTable())
                            {
                                sda.Fill(dt);
                                GridCondition.DataSource = dt;
                                GridCondition.DataBind();
                            }
                        }
                    }
                }
            }


            else if (status == "ERR")
            {

                using (SqlConnection con = new SqlConnection(constr))
                {
                    using (SqlCommand cmd = new SqlCommand("SELECT Sno as SNo ,ErrorCode as Code, ErrorDescription+' '+ErrorTrace as Description FROM OutErrorStatus Where MsgID='" + msgid + "' order by Sno"))
                    {
                        using (SqlDataAdapter sda = new SqlDataAdapter())
                        {
                            cmd.Connection = con;
                            sda.SelectCommand = cmd;
                            using (DataTable dt = new DataTable())
                            {
                                sda.Fill(dt);
                                GridCondition.DataSource = dt;
                                GridCondition.DataBind();
                            }
                        }
                    }
                }
            }


            else if (status == "REJ")
            {

                using (SqlConnection con = new SqlConnection(constr))
                {
                    using (SqlCommand cmd = new SqlCommand("SELECT Sno as SNO, ErrorID  as Code , ErrorDescription as Description FROM OutRejectStatus Where MsgID='" + msgid + "' order by Sno"))
                    {
                        using (SqlDataAdapter sda = new SqlDataAdapter())
                        {
                            cmd.Connection = con;
                            sda.SelectCommand = cmd;
                            using (DataTable dt = new DataTable())
                            {
                                sda.Fill(dt);
                                GridCondition.DataSource = dt;
                                GridCondition.DataBind();
                            }
                        }
                    }
                }
            }
            else if (status == "CNL")
            {

                using (SqlConnection con = new SqlConnection(constr))
                {
                    using (SqlCommand cmd = new SqlCommand("SELECT Sno as SNO, ConditionCde  as Code , ConditionDes as Description FROM OutCancelPermit Where MsgID='" + msgid + "' order by Sno"))
                    {
                        using (SqlDataAdapter sda = new SqlDataAdapter())
                        {
                            cmd.Connection = con;
                            sda.SelectCommand = cmd;
                            using (DataTable dt = new DataTable())
                            {
                                sda.Fill(dt);
                                GridCondition.DataSource = dt;
                                GridCondition.DataBind();
                            }
                        }
                    }
                }
            }
            else if (status == "AME")
            {

                using (SqlConnection con = new SqlConnection(constr))
                {
                    using (SqlCommand cmd = new SqlCommand("SELECT Sno as SNO, ConditionCode  as Code , ConditionDescription as Description FROM OutAMDPMT Where PermitNumber='" + Permitnum + "' order by Sno"))
                    {
                        using (SqlDataAdapter sda = new SqlDataAdapter())
                        {
                            cmd.Connection = con;
                            sda.SelectCommand = cmd;
                            using (DataTable dt = new DataTable())
                            {
                                sda.Fill(dt);
                                GridCondition.DataSource = dt;
                                GridCondition.DataBind();
                            }
                        }
                    }
                }
            }

            upout.Update();
            outheader.Update();

        }
