                        string qry11 = "select * from ReceiptLocation where Code='" + ss[0].ToString() + "'";
                        obj.dr = obj.ret_dr(qry11);
                        while (obj.dr.Read())
                        {

                            txtrecloctn.Text = obj.dr[2].ToString();
                            txtrecloctndet.Text = obj.dr[3].ToString();                            
                        }
                        lblrecloc.Visible = true;                       
                        lblrecloc.Text = "Please Check Place of Receipt Location";
                    }

                }

                else
                {
                   // string[] ss = txtrecloctn.Text.Split(':');
                    string qry11 = "select * from ReceiptLocation where Code='" + ss[0].ToString() + "'";
                    obj.dr = obj.ret_dr(qry11);
                    while (obj.dr.Read())
                    {
                        txtrecloctn.Text = obj.dr[2].ToString();
                        txtrecloctndet.Text = obj.dr[3].ToString();
                        lblrecloc.Visible = false;
                    }


                }
            }
            txtstrgeloc.Focus();

        }
