        protected void TxtCountryItem_TextChanged(object sender, EventArgs e)
        {

            if (TxtCountryItem.Text != "")
            {

                if (TxtCountryItem.Text == "IR:IRAN (ISLAMIC REP OF)" || TxtCountryItem.Text == "IQ:IRAQ" || TxtCountryItem.Text == "CD:DEOCRATIC REPUBLIC OF THE CONGO" ||
                   TxtCountryItem.Text == "CG:CONGO" || TxtCountryItem.Text == "CI:COTE DIVOIRE" || TxtCountryItem.Text == "ER:ERITREA" || TxtCountryItem.Text == "KP:KOREA, DEM PEO REP OF" || TxtCountryItem.Text == "LR:LIBERIA" || TxtCountryItem.Text == "SL:SIERRA LEONE")
                {
                    lblcoutryChk.Text = "You have Selected Controlled Country";
                }
                else
                {
                    lblcoutryChk.Text = "";
                }
                string[] ss = TxtCountryItem.Text.Split(':');
                string qry11 = "select * from Country where CountryCode='" + ss[0].ToString() + "'";
                obj.dr = obj.ret_dr(qry11);
                while (obj.dr.Read())
                {
                    TxtCountryItem.Text = obj.dr[1].ToString();
                    txtcname.Text = obj.dr[2].ToString();
                }
            }
            ChkBGIndicator.Focus();

        }

