        private void SummaryCalculate()
        {
            
            //SUM OF INVOICE
            string SumInv = "";
            string qry11 = "select Count(InvoiceNo) as InvCount from dbo.OutInvoiceDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11);
            while (obj.dr.Read())
            {
                SumInv = obj.dr[0].ToString();
                txtnoofinv.Text = SumInv;
            }
            //SUM OF ITEM
            string SumItem = "";
            string qry112 = "select Count(ItemNo) as ItemCount from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry112);
            while (obj.dr.Read())
            {
                SumItem = obj.dr[0].ToString();
                txtnoofitm.Text = SumItem;
            }

            ///Total Invoice CIF Value
            string InvoiceCIFValue = "";
            string qry112Q = "select sum(CIFSUMAmount) as InvoiceDtl from dbo.OutInvoiceDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry112Q);
            while (obj.dr.Read())
            {
                InvoiceCIFValue = obj.dr[0].ToString();
                txtcifVal.Text = InvoiceCIFValue;
            }
            //Sum of Item Amount

            string SumofItemAmount = "";
            string qry11s2Q = "select SUM(TotalLineAmount) as  TotalLineAmount  from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11s2Q);
            while (obj.dr.Read())
            {
                SumofItemAmount = obj.dr[0].ToString();
                txtitmAmt.Text = SumofItemAmount;
            }
            //TotalGSTAmount
            string TotalGSTAmount = "";
            string qry11s2 = "select SUM(GSTAmount) as  GSTAmount  from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11s2);
            while (obj.dr.Read())
            {
                TotalGSTAmount = obj.dr[0].ToString();
                txttotgstAmt.Text = TotalGSTAmount;
                txtAmtPayble.Text = TotalGSTAmount;
            }
            lblTotItemGst.Text = txttotgstAmt.Text;
            //Total CIF/FOB Value
            string TotalCIFFOBValue = "";
            string qry11sS2 = "select SUM(CIFFOB) as  GSTAmount  from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11sS2);
            while (obj.dr.Read())
            {
                TotalCIFFOBValue = obj.dr[0].ToString();
                txtfobval.Text = TotalCIFFOBValue;
            }


            string TotalGSTAmount1 = "", totalexamt = "", cusamt = "", othertaxamt = "";
            string qry11s233 = "select SUM(GSTAmount) as  GSTAmount  from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11s233);
            while (obj.dr.Read())
            {
                TotalGSTAmount1 = obj.dr[0].ToString();
                txttotgstAmt.Text = TotalGSTAmount1;                
            }

            string qry11s21 = "select SUM(ExciseDutyAmount) as  GSTAmount  from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11s21);
            while (obj.dr.Read())
            {
                totalexamt = obj.dr[0].ToString();
                txttotexAmt.Text = totalexamt;                
            }
            string qry11s22 = "select SUM(CustomsDutyAmount) as  GSTAmount  from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11s22);
            while (obj.dr.Read())
            {
                cusamt = obj.dr[0].ToString();
                txtcusdutyAmt.Text = cusamt;                
            }


            string qry11s23 = "select SUM(OtherTaxAmount) as  GSTAmount  from dbo.OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'";
            obj.dr = obj.ret_dr(qry11s23);
            while (obj.dr.Read())
            {
                othertaxamt = obj.dr[0].ToString();
                txtothtaxAmt.Text = othertaxamt;                
            }


            double T11, T22, T33, T44;
            bool AA = double.TryParse(txttotgstAmt.Text.Trim(), out T11);
            bool BB = double.TryParse(txttotexAmt.Text.Trim(), out T22);
            bool CC = double.TryParse(txtcusdutyAmt.Text.Trim(), out T33);
            bool DD = double.TryParse(txtothtaxAmt.Text.Trim(), out T44);

            if (AA && BB && CC)
                txtAmtPayble.Text = (T11 + T22 + T33 + T44).ToString();


            lblimporterparty.Text = TxtExpCRUEI.Text + "   -   " + TxtExpName.Text + " " + TxtExpName1.Text;
            if (!string.IsNullOrWhiteSpace(DrpInwardtrasMode.SelectedItem.ToString()))
            {
                if (DrpInwardtrasMode.SelectedItem.ToString().ToUpper() == "1 : Sea".ToUpper())
                {
                    INOBL.Text = TxtOceanBill.Text;
                }
                else
                {
                    INOBL.Text = txtwaybill.Text;
                }
            }
            //INOBL.Text = TxtOceanBill.Text;
            INHBLS.Text = txthblCargo.Text;
            if (!string.IsNullOrWhiteSpace(DrpOutwardtrasMode.SelectedItem.ToString()))
            {
                if (DrpOutwardtrasMode.SelectedItem.ToString().ToUpper() == "1 : Sea".ToUpper())
                {
                    lbloblval.Text = OUTWARDOcenbill.Text;
                }
                else
                {
                    lbloblval.Text = OUTWARDAirwaybill.Text;
                }
            }
            OUTHBL.Text = txtouthblCargo.Text;            
            AddDynamicLabels();
            AddDynamicItem();
            outsummery.Update();
        }        
