        protected void BtnSaveDraft_Click(object sender, EventArgs e)
        {
            ReqValidatePageLoad();
            if (GridError.DataSource != null)
            {
                GridError.Visible = true;
                POPUPERR.Show();
                POPUPERR.X = 400;
                POPUPERR.Y = 100;
            }
            else
            {


                if (Convert.ToDecimal(txtcifVal.Text) == Convert.ToDecimal(txtfobval.Text))
                {
                    if (Update == "AMEND")
                    {
                        //if (ErrorDes == "")
                        //{
                        //    POPUPERR.Hide();

                        Editdata();
                        amendinsert();
                        Response.Redirect("TranshipmentList.aspx");
                        //}
                        //else
                        //{
                        //    POPUPERR.Show();
                        //    POPUPERR.X = 400;
                        //    POPUPERR.Y = 100;
                        //}

                    }
                    else if (Update == "CANCEL")
                    {
                        Editdata();
                        Cancelinsert();
                        Response.Redirect("TranshipmentList.aspx");
                    }
                    else
                    {
                        Id = Convert.ToInt16(Session["Id"].ToString());
                        if (Id != 0)
                        {
                            Editdata();
                            InvoiceClr();
                            Itemclear();
                            Session["Edit"] = false;
                            // eid = 0;
                        }
                        else
                        {

                            int chkCode = 0;
