        protected void imgItemDelete_Click(object sender, EventArgs e)
        {

            LinkButton lnkbtn = sender as LinkButton;
            //getting particular row linkbutton
            GridViewRow gvrow = lnkbtn.NamingContainer as GridViewRow;
            //getting userid of particular row
            int employeeId = Convert.ToInt32(AddItemGrid.DataKeys[gvrow.RowIndex].Value.ToString());
            int result;
            //getting Connectin String from Web.Config
            string conString = ConfigurationManager.ConnectionStrings["Mycon"].ConnectionString;
            using (SqlConnection con = new SqlConnection(conString))
            {
                con.Open();
                SqlCommand cmd = new SqlCommand("DELETE FROM OutItemDtl where ID=" + employeeId, con);
                result = cmd.ExecuteNonQuery();

                string var = "DECLARE @SRNO bigint=0;" + Environment.NewLine;
                var = var + " UPDATE OutItemDtl SET @SRNO =ItemNo= @SRNO + 1 where PermitId='" + txt_code.Text + "'";

                cmd = new SqlCommand(var, con);
                cmd.ExecuteNonQuery();

                cmd = new SqlCommand("DELETE FROM OutCASCDtl where PermitId='" + txt_code.Text + "'", con);
                cmd.ExecuteNonQuery();
                con.Close();
                ItemNO();
            }           
            BindItemMaster();         
        }
        private void BindItemMaster()
        {
            string constr = ConfigurationManager.ConnectionStrings["Mycon"].ConnectionString;
            using (SqlConnection con = new SqlConnection(constr))
            {
                using (SqlCommand cmd = new SqlCommand("SELECT * FROM OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC' order by ItemNo"))
                {
                    using (SqlDataAdapter sda = new SqlDataAdapter())
                    {
                        cmd.Connection = con;
                        sda.SelectCommand = cmd;
                        using (DataTable dt = new DataTable())
                        {
                            sda.Fill(dt);
                            AddItemGrid.DataSource = dt;
                            AddItemGrid.DataBind();
                        }
                    }
                }
            }
        }
