        private void AddDynamicLabels()
        {
            string totinvAmt = "";
            string ConString = ConfigurationManager.ConnectionStrings["Mycon"].ConnectionString;
            SqlConnection con = new SqlConnection(ConString);
            string CmdString = "select TIAmount,TICurrency  from dbo.OutInvoiceDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'  ORDER BY TICurrency DESC";
            SqlCommand cmd = new SqlCommand(CmdString, con);
            con.Open();
            SqlDataReader reader = cmd.ExecuteReader();
            while (reader.Read())
            {
                Label lbl = new Label();
                lbl.Text = reader["TICurrency"].ToString() + " " + reader["TIAmount"].ToString();
                lbltotinvAmt.Text = reader["TIAmount"].ToString();
                totinvAmt = totinvAmt + " " + lbl.Text + " " + Environment.NewLine;

                lbl.BackColor = System.Drawing.Color.WhiteSmoke;
                lbl.BorderStyle = BorderStyle.Solid;
                lbl.BorderWidth = 1;
                lbl.Width = 150;

                div7.Controls.Add(lbl);
                div7.Controls.Add(new LiteralControl("<br />"));
            }
            lblinvoiceAmt.Text = totinvAmt;
            
            con.Close();
        }
        private void AddDynamicItem()
        {
            string totinvAmt = "";
            string ConString = ConfigurationManager.ConnectionStrings["Mycon"].ConnectionString;
            SqlConnection con = new SqlConnection(ConString);
            string CmdString = "select distinct (UnitPriceCurrency), sum(TotalLineAmount) as TotalLineAmount from OutItemDtl where PermitId='" + txt_code.Text + "' and MessageType='OUTDEC'  GROUP BY UnitPriceCurrency ORDER BY UnitPriceCurrency DESC";
            SqlCommand cmd = new SqlCommand(CmdString, con);
            con.Open();
            SqlDataReader reader = cmd.ExecuteReader();
            while (reader.Read())
            {
                Label lbl = new Label();
                lbl.Text = reader["UnitPriceCurrency"].ToString() + " " + reader["TotalLineAmount"].ToString();
                Label1.Text = reader["TotalLineAmount"].ToString();
                lbl.BackColor = System.Drawing.Color.WhiteSmoke;
                lbl.BorderStyle = BorderStyle.Solid;
                lbl.BorderWidth = 1;
                lbl.Width = 150;
                totinvAmt = totinvAmt + " " + lbl.Text + " " + Environment.NewLine;
                dIViTEMzzz.Controls.Add(lbl);
                dIViTEMzzz.Controls.Add(new LiteralControl("<br />"));
            }
            Label1.Text = totinvAmt;
            con.Close();
        }
      
