            }
            else if (string.IsNullOrWhiteSpace(ConsigneeAddress.Text))
            {
                ScriptManager.RegisterClientScriptBlock(this, this.GetType(), "Notify", "alert('Notification : The Consignee Address Is Empty');", true);
            }
            else
            {
                string Code = "";
                string qry11 = "SELECT ConsigneeCode FROM OutConsignee where ConsigneeCode='" + ConsigneeCode.Text + "'";
                obj.dr = obj.ret_dr(qry11);
                while (obj.dr.Read())
                {
                    Code = obj.dr[0].ToString();
                }
                if (Code == "")
                {
                    string Touch_user = Session["UserId"].ToString();
                    string strTime = System.DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                    string StrQuery = ("INSERT INTO [dbo].[OutConsignee] ([ConsigneeCode],[ConsigneeName],[ConsigneeName1],[ConsigneeCRUEI],[ConsigneeAddress],[ConsigneeAddress1],[ConsigneeCity],[ConsigneeSub],ConsigneeSubDivi,[ConsigneePostal],[ConsigneeCountry],[TouchUser],[TouchTime])  VALUES ('" + ConsigneeCode.Text + "','" + ConsigneeName.Text + "','" + ConsigneeName1.Text + "','" + ConsigneeCRUEI.Text + "','" + ConsigneeAddress.Text + "','" + ConsigneeAddress1.Text + "','" + ConsigneeCity.Text + "','" + ConsigneeSub.Text + "','" + ConsigneeSubDivi.Text + "','" + ConsigneePostal.Text + "','" + ConsigneeCountry.Text + "','" + Touch_user + "',Convert(VARCHAR,'" + strTime + "',108))");
                    obj.exec(StrQuery);
                    BindConsignee();
                }
                else
                {
                    ScriptManager.RegisterClientScriptBlock(this, this.GetType(), "Notify", "alert('Notification : The Inward Code Already Exist...');", true);
                    //Response.Write("The Inward Code Already Exist..");
                }


                chkeu.Focus();
            }

        }
