        protected void ChkSea_CheckedChanged(object sender, EventArgs e)
        {
            if (chkaeo.Checked == true && chkcwc.Checked == true && ChkSea1.Checked == true)
            {
                AEO.Visible = true;
                CWC.Visible = true;
                SEA.Visible = true;

                return;
            }
            else if (chkaeo.Checked == true)
            {
                AEO.Visible = true;
                CWC.Visible = false;
                SEA.Visible = false;
            }
            else if (chkcwc.Checked == true)
            {
                AEO.Visible = false;
                CWC.Visible = true;
                SEA.Visible = false;
            }
            else if (ChkSea1.Checked == true)
            {
                AEO.Visible = false;
                CWC.Visible = false;
                SEA.Visible = true;
            }
            else
            {
                AEO.Visible = false;
                CWC.Visible = false;
                SEA.Visible = false;
            }
        }

