                    txtEndUserDec4_TextChanged(null, null);
                    //DrpP3.SelectedItem.Text = obj.dr["ProductUOM"].ToString();
                }
                SqlDataAdapter sda1 = new SqlDataAdapter(cmd1);
                DataTable dt = new DataTable();
                sda1.Fill(dt);
                if (dt.Rows.Count <= 0)
                {
                    dt.Rows.Add();
