        public DataTable GetExpFromDataBase(string searchtext)
        {
            DataTable _objdt = new DataTable();
            var a = TxtCountryItem.Text;

            string str3 = "SELECT * FROM OutExporter where OutUserName Like '%" + ExporterSearch.Text + "%' order by Id desc";
            obj.dr = obj.ret_dr(str3);
            if (obj.dr.HasRows)
            {
                ExporterPartyGrid.DataSource = obj.dr;

            }
            else
            {
                //Empty DataTable to execute the “else-condition”  
                DataTable dt = new DataTable();
                ExporterPartyGrid.DataSource = dt;
                ExporterPartyGrid.DataBind();
            }
            SqlConnection con = new SqlConnection(sqlconn);
            SqlDataAdapter _objda = new SqlDataAdapter(str3, con);
            con.Close();
            _objda.Fill(_objdt);
            return _objdt;
        }
