        protected void CancelDocDelete_Click(object sender, EventArgs e)
        {
            LinkButton lnkbtn = sender as LinkButton;
            //getting particular row linkbutton
            GridViewRow gvrow = lnkbtn.NamingContainer as GridViewRow;
            //getting userid of particular row
            int employeeId = Convert.ToInt32(GridCancelDoc.DataKeys[gvrow.RowIndex].Value.ToString());
            int result;
            //getting Connectin String from Web.Config
            string conString = ConfigurationManager.ConnectionStrings["Mycon"].ConnectionString;
            using (SqlConnection con = new SqlConnection(conString))
            {
                con.Open();
                SqlCommand cmd = new SqlCommand("DELETE FROM OutCanFile where ID=" + employeeId, con);
                result = cmd.ExecuteNonQuery();
                con.Close();
            }
            if (result == 1)
            {
                BindGridCancel();
            }
        }




        protected void BtnCancelUp_Click(object sender, EventArgs e)
        {
            foreach (HttpPostedFile postedFile in FileUpload2.PostedFiles)
            {
                string filename = Path.GetFileName(postedFile.FileName);
                string contentType = postedFile.ContentType;
                using (Stream fs = postedFile.InputStream)
                {
                    using (BinaryReader br = new BinaryReader(fs))
                    {
                        byte[] bytes = br.ReadBytes((Int32)fs.Length);
                        string constr = ConfigurationManager.ConnectionStrings["Mycon"].ConnectionString;
                        using (SqlConnection con = new SqlConnection(constr))
                        {
                            string Touch_user = Session["UserId"].ToString();
                            string Code = txt_code.Text;
                            string DocType = DrpDocumenttype.SelectedItem.ToString();
                            string strTime = System.DateTime.Now.ToString("yyyy/MM/dd");
                            string query = "insert into OutCanFile values (@Name, @ContentType, @Data,@DocumentType,@InPaymentId,@TouchUser,@TouchTime)";
                            using (SqlCommand cmd = new SqlCommand(query))
                            {

                                cmd.Connection = con;
                                cmd.Parameters.AddWithValue("@Name", filename);
                                cmd.Parameters.AddWithValue("@ContentType", contentType);
                                cmd.Parameters.AddWithValue("@Data", bytes);
                                cmd.Parameters.AddWithValue("@DocumentType", DocType);
                                cmd.Parameters.AddWithValue("@InPaymentId", Code);
                                cmd.Parameters.AddWithValue("@TouchUser", Touch_user);
                                cmd.Parameters.AddWithValue("@TouchTime", strTime);
                                con.Open();
                                cmd.ExecuteNonQuery();
                                con.Close();
                                BindGridCancel();
                            }
                        }
                    }
                }
            }
        }

        protected void DrpCOType_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (DrpCOType.SelectedItem.ToString() == "--Select--")
            {
                coo.Visible = false;
                cor.Visible = false;
                manufact.Visible = false;
            }
            else if (DrpCOType.SelectedItem.ToString() == "TX : Application for textile products")
            {
                textile.Visible = true;
                cor.Visible = true;
                manufact.Visible = true;
                coo.Visible = true;

            }
            else if (DrpCOType.SelectedItem.ToString() == "NH : Application for non-textile products (Collection at Headquarters)")
            {
                textile.Visible = false;
                cor.Visible = true;
                manufact.Visible = true;
                coo.Visible = true;
            }
            else if (DrpCOType.SelectedItem.ToString() == "NA : Application for non-textile products (Collection at Airport)")
            {
                textile.Visible = false;
                cor.Visible = true;
                manufact.Visible = true;
                coo.Visible = true;
            }

            else
            {
                coo.Visible = true;
                textile.Visible = false;
               
            }

            DrpBGIndicator.Focus();
            outparty.Update();
            outitem.Update();
            
        }

        protected void DrpCargoPackType_SelectedIndexChanged(object sender, EventArgs e)
        {
            string TransMode = DrpCargoPackType.SelectedItem.ToString();
            if (DrpCargoPackType.SelectedItem.ToString() != "--Select--")
            {

                if (TransMode == "9: Containerized")
                {
                    gvAddrow.Visible = true;
                }
                else
                {
                    gvAddrow.Visible = false;
                }
            }
            else
            {
                gvAddrow.Visible = false;
            }

            string[] dectyp = DrpDecType.SelectedItem.Text.Split(':');
            if (dectyp[0].ToString() == "DRT ")
            {
                DrpInwardtrasMode.Focus();
            }
            else
            {
                DrpOutwardtrasMode.Focus();
            }
            outcargo.Update();
            outitem.Update();

        }


