        protected void DrpFinalDesCountry_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (DrpFinalDesCountry.SelectedItem.ToString() != "--Select--")
            {
                if (DrpFinalDesCountry.SelectedItem.ToString() == "IR : IRAN (ISLAMIC REP OF)" || DrpFinalDesCountry.SelectedItem.ToString() == "IQ : IRAQ" || DrpFinalDesCountry.SelectedItem.ToString() == "CD : DEOCRATIC REPUBLIC OF THE CONGO" ||
                    DrpFinalDesCountry.SelectedItem.ToString() == "CG : CONGO" || DrpFinalDesCountry.SelectedItem.ToString() == "CI : COTE DIVOIRE" || DrpFinalDesCountry.SelectedItem.ToString() == "ER : ERITREA" || DrpFinalDesCountry.SelectedItem.ToString() == "KP : KOREA, DEM PEO REP OF" || DrpFinalDesCountry.SelectedItem.ToString() == "LR : LIBERIA" || DrpFinalDesCountry.SelectedItem.ToString() == "SL : SIERRA LEONE")
                {
                    lblfinalcountry.Text = "You have Selected Controlled Country";
                    lblcoutryChk.Text = "You have Selected Controlled Country";
                }
                else
                {
                    lblfinalcountry.Text = "";
                    lblcoutryChk.Text = "";
                }
            }
            chkSea.Focus();
        }

        protected void TxtInvQty_TextChanged(object sender, EventArgs e)
        {
            string qry11 = "select UOM from HSCode where HSCode='" + TxtHSCodeItem.Text + "'";
            obj.dr = obj.ret_dr(qry11);
            while (obj.dr.Read())
            {
                string UOm = obj.dr[0].ToString();


                if (UOm == "TEN")
                {
                    double a;
                    bool isAValid = double.TryParse(TxtInvQty.Text.Trim(), out a);

                    if (isAValid)
                        TxtHSQuantity.Text = (a / 10).ToString();

                }
                else if (UOm == "TPR")
                {
                    double a;
                    bool isAValid = double.TryParse(TxtInvQty.Text.Trim(), out a);

                    if (isAValid)
                        TxtHSQuantity.Text = (a / 10).ToString();

                }

                else if (UOm == "CEN")
                {
                    double a;
                    bool isAValid = double.TryParse(TxtInvQty.Text.Trim(), out a);

                    if (isAValid)
                        TxtHSQuantity.Text = (a / 100).ToString();

                }

                else if (UOm == "MIL")
                {
                    double a;
                    bool isAValid = double.TryParse(TxtInvQty.Text.Trim(), out a);

                    if (isAValid)
                        TxtHSQuantity.Text = (a / 1000).ToString();

                }

                else if (UOm == "TNE")
                {
                    double a;
                    bool isAValid = double.TryParse(TxtInvQty.Text.Trim(), out a);

                    if (isAValid)
                        TxtHSQuantity.Text = (a / 1000).ToString();

                }
                else if (UOm == "MTK")
                {
                    double a;
                    bool isAValid = double.TryParse(TxtInvQty.Text.Trim(), out a);

                    if (isAValid)
                        TxtHSQuantity.Text = (a * 3.213).ToString();

                }
                else if (UOm == "LTR")
                {
                    double a;
                    bool isAValid = double.TryParse(TxtInvQty.Text.Trim(), out a);

                    if (isAValid)
                        TxtHSQuantity.Text = (a * 1.25).ToString();
                }
                else if (UOm == "NMB")
                {
                    //  string tt;
                    // string [] tokens;
                    double a;
                    bool ss;
