        protected void BtnDFC_Click(object sender, EventArgs e)
        {
            if (DFCGrid.Rows.Count <= 0)
            {
                SetInitialRowdfc();
            }
            else
            {
                AddNewRowToGriddfcCWC();
            }
        }
        private void SetInitialRowdfc()
        {

            DataTable dt = new DataTable();

            DataRow dr = null;

            dt.Columns.Add(new DataColumn("RowNumber", typeof(string)));

            dt.Columns.Add(new DataColumn("Processing Code1", typeof(string)));

            dt.Columns.Add(new DataColumn("Processing Code2", typeof(string)));

            dt.Columns.Add(new DataColumn("Processing Code3", typeof(string)));

            dr = dt.NewRow();

            dr["RowNumber"] = 1;

            dr["Processing Code1"] = string.Empty;

            dr["Processing Code2"] = string.Empty;

            dr["Processing Code3"] = string.Empty;

            dt.Rows.Add(dr);

            //dr = dt.NewRow();



            //Store the DataTable in ViewState

            ViewState["DFCWC"] = dt;

            DFCGrid.DataSource = dt;

            DFCGrid.DataBind();
            DFCGrid.Columns[0].Visible = false;

        }
        private void AddNewRowToGriddfcCWC()
        {

            int rowIndex = 0;



            if (ViewState["DFCWC"] != null)
            {

                DataTable dtCurrentTable = (DataTable)ViewState["DFCWC"];

                DataRow drCurrentRow = null;

                if (dtCurrentTable.Rows.Count > 0)
                {

                    for (int i = 1; i <= dtCurrentTable.Rows.Count; i++)
                    {

                        //extract the TextBox values

                        TextBox box1 = (TextBox)DFCGrid.Rows[rowIndex].Cells[1].FindControl("TextBox1");

                        TextBox box2 = (TextBox)DFCGrid.Rows[rowIndex].Cells[2].FindControl("TextBox2");

                        TextBox box3 = (TextBox)DFCGrid.Rows[rowIndex].Cells[3].FindControl("TextBox3");



                        drCurrentRow = dtCurrentTable.NewRow();

                        drCurrentRow["RowNumber"] = i + 1;



                        dtCurrentTable.Rows[i - 1]["Processing Code1"] = box1.Text;

                        dtCurrentTable.Rows[i - 1]["Processing Code2"] = box2.Text;

                        dtCurrentTable.Rows[i - 1]["Processing Code3"] = box3.Text;



                        rowIndex++;

                    }

                    dtCurrentTable.Rows.Add(drCurrentRow);

                    ViewState["DFCWC"] = dtCurrentTable;



                    DFCGrid.DataSource = dtCurrentTable;

                    DFCGrid.DataBind();
                    DFCGrid.Columns[0].Visible = false;
                }

            }

            else
            {

                Response.Write("ViewState is null");

            }



            //Set Previous Data on Postbacks

            SetPreviousDatadfcCWC();

        }
        private void SetPreviousDatadfcCWC()
        {

            int rowIndex = 0;

            if (ViewState["DFCWC"] != null)
            {

                DataTable dt = (DataTable)ViewState["DFCWC"];

                if (dt.Rows.Count > 0)
                {

                    for (int i = 0; i < dt.Rows.Count; i++)
                    {

                        TextBox box1 = (TextBox)DFCGrid.Rows[rowIndex].Cells[1].FindControl("TextBox1");

                        TextBox box2 = (TextBox)DFCGrid.Rows[rowIndex].Cells[2].FindControl("TextBox2");

                        TextBox box3 = (TextBox)DFCGrid.Rows[rowIndex].Cells[3].FindControl("TextBox3");



                        box1.Text = dt.Rows[i]["Processing Code1"].ToString();

                        box2.Text = dt.Rows[i]["Processing Code2"].ToString();

                        box3.Text = dt.Rows[i]["Processing Code3"].ToString();



                        rowIndex++;

                    }

                }

            }

        }

        protected void DFCGrid_RowDeleting(object sender, GridViewDeleteEventArgs e)
        {
            if (ViewState["DFCWC"] != null)
            {
                DataTable dt = (DataTable)ViewState["DFCWC"];
                DataRow drCurrentRow = null;
                int rowIndex = Convert.ToInt32(e.RowIndex);
                if (dt.Rows.Count > 1)
                {
                    dt.Rows.Remove(dt.Rows[rowIndex]);
                    drCurrentRow = dt.NewRow();
                    ViewState["DFCWC"] = dt;
                    DFCGrid.DataSource = dt;
                    DFCGrid.DataBind();

                    for (int i = 0; i < CWCGrid.Rows.Count - 1; i++)
                    {
                        DFCGrid.Rows[i].Cells[0].Text = Convert.ToString(i + 1);
                    }
                    SetPreviousDatadfcCWC();
                }
            }
        }

        protected void CNBGrid_RowDeleting(object sender, GridViewDeleteEventArgs e)
        {
            if (ViewState["CNB"] != null)
            {
                DataTable dt = (DataTable)ViewState["CNB"];
                DataRow drCurrentRow = null;
                int rowIndex = Convert.ToInt32(e.RowIndex);
                if (dt.Rows.Count > 1)
                {
                    dt.Rows.Remove(dt.Rows[rowIndex]);
                    drCurrentRow = dt.NewRow();
                    ViewState["CNB"] = dt;
                    CNBGrid.DataSource = dt;
                    CNBGrid.DataBind();

