        protected void InwardAdd_Click(object sender, EventArgs e)
        {
            if (string.IsNullOrWhiteSpace(InwardCode.Text))
            {
                ScriptManager.RegisterClientScriptBlock(this, this.GetType(), "Notify", "alert('Notification : The Inward Code Code Is Empty');", true);
            }
            else if (string.IsNullOrWhiteSpace(InwardName.Text))
            {
                ScriptManager.RegisterClientScriptBlock(this, this.GetType(), "Notify", "alert('Notification : The Inward Code Name Is Empty');", true);
            }
            else if (string.IsNullOrWhiteSpace(InwardCRUEI.Text))
            {
                ScriptManager.RegisterClientScriptBlock(this, this.GetType(), "Notify", "alert('Notification : The Inward Code UEI Is Empty');", true);
            }
            else
            {
                string Code = "";
                string qry11 = "SELECT Code FROM InwardCarrierAgent where Code='" + InwardCode.Text + "'";

                obj.dr = obj.ret_dr(qry11);

                while (obj.dr.Read())
                {
                    Code = obj.dr[0].ToString();

                }
                if (Code == "")
                {
                    string Touch_user = Session["UserId"].ToString();

                    string strTime = System.DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                    string StrQuery = ("INSERT INTO [dbo].[InwardCarrierAgent] ([Code],[Name],[Name1],[CRUEI],[TouchUser],[TouchTime]) VALUES ('" + InwardCode.Text + "','" + InwardName.Text + "','" + InwardName1.Text + "','" + InwardCRUEI.Text + "','" + Touch_user + "',Convert(VARCHAR,'" + strTime + "',108))");
                    obj.exec(StrQuery);
                    BindInward();
                }
                else
                {
                    ScriptManager.RegisterClientScriptBlock(this, this.GetType(), "Notify", "alert('Notification : The Inward Code Already Exist...');", true);
                    //Response.Write("The Inward Code Already Exist..");
                }

                OutwardCode.Focus();
            }
        }

